import './App.css';
import SearchBar from './components/SearchBar';
import ErrorMessage from './components/ErrorMessage';
import WeatherCard from './components/WeatherCard';
import Loader from './components/Loader';
import { useEffect, useState } from 'react';

const App = () => {
  const [city, setCity] = useState('');
  const [tcity, setTcity] = useState('');
  const [temperature, setTemperature] = useState('');
  const [wind, setWind] = useState('');
  const [humidity, setHumidity] = useState('');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const API_KEY = "AsrN9YmNZyUW3G4VTP6mRgjPLPA6bzF5"; // api key

  // 🔥 Fetch Weather Function
  const fetchWeather = async (cityName) => {
    try {
      setLoading(true);
      setError('');

      const res = await fetch(
        `https://api.tomorrow.io/v4/weather/realtime?location=${cityName}&apikey=${API_KEY}`
      );

      const data = await res.json();
      console.log(data);

      // Extract data
      const values = data.data.values;

      setTcity(cityName);
      setTemperature(`Temperature: ${values.temperature}°C`);
      setWind(`Wind Speed: ${values.windSpeed} m/s`);
      setHumidity(`Humidity: ${values.humidity}%`);

    } catch (err) {

      setError("Failed to fetch weather");
    } finally {
      setLoading(false);
    }
  };

  // Default city load
  useEffect(() => {
    fetchWeather("Visakhapatnam");
  }, []);

  //  Search handler
  const checkWeather = () => {
    if (!city) {
      setError("Enter city name");
      return;
    }
    fetchWeather(city);
    setCity('');
  };

  return (
    <div className="screen">
      <div className="main">
        <h1>Weather App</h1>

        <SearchBar
          city={city}
          setCity={setCity}
          onSearch={checkWeather}
        />

        {loading && <Loader />}
        {error && <ErrorMessage message={error} />}

        {tcity && !loading && (
          <WeatherCard
            city={tcity}
            temperature={temperature}
            wind={wind}
            humidity={humidity}
          />
        )}
      </div>
    </div>
  );
};

export default App;
